import { Bar } from "react-chartjs-2";

const EmotionChart = ({ data }) => {
  const chartData = {
    labels: data.map(item => item._id),
    datasets: [{
      label: "Emotion Count",
      data: data.map(item => item.count),
      backgroundColor: "rgba(75,192,192,0.6)"
    }]
  };

  return <Bar data={chartData} />;
};

export default EmotionChart;
